**The debounce function delays the execution of a function until a specified time has passed since the last invocation.**

```javascript
function debounce(func, wait) {
    let timeout;
    return function(...args) {
        clearTimeout(timeout);
        timeout = setTimeout(() => func(...args), wait);
    };
}

// Example usage:
const debouncedLogger = debounce((message) => console.log(message), 500);
debouncedLogger("Hello"); // will log "Hello" after 500ms
debouncedLogger("World"); // will clear previous log and log "World" after 500ms
```
